CREATE TABLE IF NOT EXISTS requests (id SERIAL PRIMARY KEY, scraper SMALLINT NOT NULL, url VARCHAR(255) NOT NULL, "method" VARCHAR(10) NOT NULL, "type" VARCHAR(20) NOT NULL, requested_at TIMESTAMP NOT NULL, duration BIGINT NOT NULL, status_code SMALLINT NOT NULL, "result" VARCHAR(20) NULL, send_bytes BIGINT NULL, receive_bytes BIGINT NULL, server_build VARCHAR(40) NULL, server_build_ago BIGINT NULL, server_db_queries INT NULL, server_db_cached INT NULL, server_cache_hits INT NULL, server_cache_misses INT NULL, server_request_per_second DOUBLE PRECISION NULL, server_active_users_sign_in INT NULL, server_active_users_visitors INT NULL, request_iteration INT NOT NULL, CONSTRAINT fk_requests_request_iteration__id FOREIGN KEY (request_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT chk_requests_unsigned_integer_send_bytes CHECK (send_bytes BETWEEN 0 AND 4294967295), CONSTRAINT chk_requests_unsigned_integer_receive_bytes CHECK (receive_bytes BETWEEN 0 AND 4294967295), CONSTRAINT chk_requests_unsigned_short_server_db_queries CHECK (server_db_queries BETWEEN 0 AND 65535), CONSTRAINT chk_requests_unsigned_short_server_db_cached CHECK (server_db_cached BETWEEN 0 AND 65535), CONSTRAINT chk_requests_unsigned_short_server_cache_hits CHECK (server_cache_hits BETWEEN 0 AND 65535), CONSTRAINT chk_requests_unsigned_short_server_cache_misses CHECK (server_cache_misses BETWEEN 0 AND 65535), CONSTRAINT chk_requests_unsigned_short_server_active_users_sign_in CHECK (server_active_users_sign_in BETWEEN 0 AND 65535), CONSTRAINT chk_requests_unsigned_short_server_active_users_visitors CHECK (server_active_users_visitors BETWEEN 0 AND 65535));
